17	// NewConfigLoader creates a new configuration loader with validation
18	func NewConfigLoader() (*ConfigLoader, error) {
19		workingDir, err := os.Getwd()
20		if err != nil {
21			return nil, fmt.Errorf("failed to get working directory: %w", err)
22		}
23		return NewConfigLoaderWithWorkingDir(workingDir)
24	}
25	
26	// NewConfigLoaderWithWorkingDir creates a new configuration loader with a specific working directory
27	func NewConfigLoaderWithWorkingDir(workingDir string) (*ConfigLoader, error) {
28		validator, err := NewValidator()
29		if err != nil {
30			return nil, fmt.Errorf("failed to create validator: %w", err)
31		}
32	
33		return &ConfigLoader{
34			validator:  validator,
35			workingDir: workingDir,
36		}, nil
37	}
