39	// LoadConfig loads configuration from .ddx/config.yaml only
40	func (cl *ConfigLoader) LoadConfig() (*NewConfig, error) {
41		// Only support new format: .ddx/config.yaml
42		configPath := filepath.Join(cl.workingDir, ".ddx", "config.yaml")
43		if _, err := os.Stat(configPath); err != nil {
44			return nil, fmt.Errorf("no configuration file found at %s", configPath)
45		}
46	
47		return cl.loadNewFormat(configPath)
48	}
49	
50	// LoadConfigFromPath loads configuration from a specific path (new format only)
51	func (cl *ConfigLoader) LoadConfigFromPath(path string) (*NewConfig, error) {
52		// Convert relative path to absolute based on working directory
53		if !filepath.IsAbs(path) {
54			path = filepath.Join(cl.workingDir, path)
55		}
56	
57		return cl.loadNewFormat(path)
58	}
59	
60	// loadNewFormat loads and validates the new configuration format
61	func (cl *ConfigLoader) loadNewFormat(path string) (*NewConfig, error) {
62		// Read file
63		data, err := os.ReadFile(path)
64		if err != nil {
65			return nil, fmt.Errorf("failed to read config file %s: %w", path, err)
66		}
67	
68		// Validate using two-phase validation
69		if err := cl.validator.Validate(data); err != nil {
70			return nil, fmt.Errorf("configuration validation failed: %w", err)
71		}
72	
73		// Parse YAML into new config structure
74		var config NewConfig
75		if err := yaml.Unmarshal(data, &config); err != nil {
76			return nil, fmt.Errorf("failed to parse config YAML from %s: %w", path, err)
77		}
78	
79		// Apply defaults to missing fields
80		config.ApplyDefaults()
81	
82		return &config, nil
83	}
84	
85	// SaveConfig saves configuration in the new format
86	func (cl *ConfigLoader) SaveConfig(config *NewConfig, path string) error {
87		// Convert relative path to absolute based on working directory
88		if !filepath.IsAbs(path) {
89			path = filepath.Join(cl.workingDir, path)
90		}
91	
92		// Create directory if it doesn't exist
93		dir := filepath.Dir(path)
94		if err := os.MkdirAll(dir, 0755); err != nil {
95			return fmt.Errorf("failed to create config directory %s: %w", dir, err)
96		}
97	
98		// Marshal to YAML
99		data, err := yaml.Marshal(config)
100		if err != nil {
101			return fmt.Errorf("failed to marshal config: %w", err)
102		}
103	
104		// Validate before saving
105		if err := cl.validator.Validate(data); err != nil {
106			return fmt.Errorf("config validation failed before save: %w", err)
107		}
108	
109		// Write file with secure permissions
110		if err := os.WriteFile(path, data, 0644); err != nil {
111			return fmt.Errorf("failed to write config file %s: %w", path, err)
112		}
113	
114		return nil
115	}
116	
117	// DetectConfigFormat determines if .ddx/config.yaml exists in working directory
118	func (cl *ConfigLoader) DetectConfigFormat() (string, string, error) {
119		configPath := filepath.Join(cl.workingDir, ".ddx", "config.yaml")
120		if _, err := os.Stat(configPath); err == nil {
121			return "new", configPath, nil
122		}
123	
124		return "none", "", fmt.Errorf("no configuration file found at %s", configPath)
125	}
