1	// Package main implements the Go-specific production-reachability check
2	// conforming to the REACH-PROTO check protocol (see cli/internal/checks/protocol.go).
3	//
4	// It reports newly-added Go functions/methods that are not reachable from the
5	// project's configured entry roots, using golang.org/x/tools/cmd/deadcode
6	// (Rapid Type Analysis) as the underlying reachability engine.
7	package main
8	
9	import (
10		"bufio"
11		"encoding/json"
12		"flag"
13		"fmt"
14		"go/ast"
15		"go/parser"
16		"go/token"
17		"os"
18		"os/exec"
19		"path/filepath"
20		"strings"
21	)
22	
23	type violation struct {
24		File   string `json:"file,omitempty"`
25		Line   int    `json:"line,omitempty"`
26		Symbol string `json:"symbol,omitempty"`
27		Kind   string `json:"kind,omitempty"`
28		Detail string `json:"detail,omitempty"`
29	}
30	
31	type result struct {
32		Status     string      `json:"status"`
33		Message    string      `json:"message,omitempty"`
34		Violations []violation `json:"violations,omitempty"`
35	}
36	
37	func main() {
38		var (
39			moduleDir     string
40			packagesArg   string
41			deadcodeBin   string
42			beadsFile     string
43			checkName     string
44		)
45		flag.StringVar(&moduleDir, "module-dir", ".", "Directory holding the go.mod from which deadcode is run (relative to PROJECT_ROOT)")
46		flag.StringVar(&packagesArg, "packages", "./...", "Comma-separated package patterns passed to deadcode")
47		flag.StringVar(&deadcodeBin, "deadcode", "", "Path to deadcode binary; default uses 'go run golang.org/x/tools/cmd/deadcode@v0.42.0'")
48		flag.StringVar(&beadsFile, "beads-file", ".ddx/beads.jsonl", "Path to beads.jsonl (relative to PROJECT_ROOT)")
49		flag.StringVar(&checkName, "name", "", "Override check name (default from CHECK_NAME env)")
50		flag.Parse()
51	
52		projectRoot := envOr("PROJECT_ROOT", "")
53		evidenceDir := envOr("EVIDENCE_DIR", "")
54		diffBase := envOr("DIFF_BASE", "")
55		diffHead := envOr("DIFF_HEAD", "HEAD")
56		if checkName == "" {
57			checkName = envOr("CHECK_NAME", "production-reachability")
58		}
59		if projectRoot == "" || evidenceDir == "" {
60			emitFatal(evidenceDir, checkName, "missing required env: PROJECT_ROOT and EVIDENCE_DIR must be set")
61			return
62		}
63		if err := os.MkdirAll(evidenceDir, 0o755); err != nil {
64			emitFatal(evidenceDir, checkName, "create evidence dir: "+err.Error())
65			return
66		}
67	
68		res := run(runArgs{
69			ProjectRoot: projectRoot,
70			ModuleDir:   moduleDir,
71			Packages:    splitCSV(packagesArg),
72			DeadcodeBin: deadcodeBin,
73			BeadsFile:   filepath.Join(projectRoot, beadsFile),
74			DiffBase:    diffBase,
75			DiffHead:    diffHead,
76			EntryRoots:  splitCSV(packagesArg),
77		})
78	
79		writeResult(filepath.Join(evidenceDir, checkName+".json"), res)
80	}
81	
82	type runArgs struct {
83		ProjectRoot string
84		ModuleDir   string
85		Packages    []string
86		EntryRoots  []string
87		DeadcodeBin string
88		BeadsFile   string
89		DiffBase    string
90		DiffHead    string
91	}
92	
93	func run(a runArgs) result {
94		if a.DiffBase == "" || a.DiffBase == a.DiffHead {
95			return result{Status: "pass", Message: "no diff range; nothing to evaluate"}
96		}
97	
98		changedGoFiles, err := gitChangedGoFiles(a.ProjectRoot, a.DiffBase, a.DiffHead)
99		if err != nil {
100			return result{Status: "error", Message: "git diff: " + err.Error()}
101		}
102		if len(changedGoFiles) == 0 {
103			return result{Status: "pass", Message: "no non-test Go files changed"}
104		}
105	
106		newSyms, err := newSymbols(a.ProjectRoot, a.DiffBase, changedGoFiles)
107		if err != nil {
108			return result{Status: "error", Message: "scan new symbols: " + err.Error()}
109		}
110		if len(newSyms) == 0 {
111			return result{Status: "pass", Message: "no new top-level functions or methods added"}
112		}
113	
114		deadSet, err := runDeadcode(a)
115		if err != nil {
116			return result{Status: "error", Message: "deadcode: " + err.Error()}
117		}
118	
119		var violations []violation
120		for _, s := range newSyms {
121			if !isDead(s, deadSet) {
122				continue
123			}
124			ann := s.Annotation
125			if ann != "" {
126				ok, why := validatePending(a.BeadsFile, ann)
127				if ok {
128					continue
129				}
130				violations = append(violations, violation{
131					File:   relPath(a.ProjectRoot, s.AbsFile),
132					Line:   s.Line,
133					Symbol: s.Symbol,
134					Kind:   "invalid_annotation",
135					Detail: fmt.Sprintf("// wiring:pending %s rejected: %s", ann, why),
136				})
137				continue
138			}
139			violations = append(violations, violation{
140				File:   relPath(a.ProjectRoot, s.AbsFile),
141				Line:   s.Line,
142				Symbol: s.Symbol,
143				Kind:   "unreachable",
144				Detail: fmt.Sprintf("no path from entry roots: %s", strings.Join(a.EntryRoots, ",")),
145			})
146		}
147	
148		if len(violations) == 0 {
149			return result{Status: "pass", Message: fmt.Sprintf("%d new symbol(s) all reachable from entry roots", len(newSyms))}
150		}
151		return result{
152			Status:     "block",
153			Message:    fmt.Sprintf("%d new symbol(s) unreachable from entry roots", len(violations)),
154			Violations: violations,
155		}
156	}
157	
158	// symbol describes one newly-added top-level function or method declaration
159	// from the worktree side of the diff.
160	type symbol struct {
161		AbsFile    string // absolute path
162		Line       int    // declaration line in HEAD
163		Symbol     string // "Func" or "(*T).Method" or "T.Method"
164		Annotation string // bead-id named in `// wiring:pending <bead-id>`, else ""
165	}
166	
167	// newSymbols returns top-level FuncDecls present in the worktree (HEAD)
168	// version of each changed file but absent from the DIFF_BASE version,
169	// keyed by (file, qualified symbol name). Test files are skipped.
170	func newSymbols(projectRoot, diffBase string, files []string) ([]symbol, error) {
171		var out []symbol
172		for _, rel := range files {
173			abs := filepath.Join(projectRoot, rel)
174			newSrc, err := os.ReadFile(abs)
175			if err != nil {
176				// File deleted in HEAD — nothing to add.
177				continue
178			}
179			oldSrc, _ := gitShow(projectRoot, diffBase, rel) // empty on add
180			oldDecls := declSet(oldSrc, rel)
181			fset := token.NewFileSet()
182			f, err := parser.ParseFile(fset, abs, newSrc, parser.ParseComments)
