323	func runDeadcode(a runArgs) (map[deadKey]deadcodeFunction, error) {
324		dir := filepath.Join(a.ProjectRoot, a.ModuleDir)
325		args := []string{"-json"}
326		args = append(args, a.Packages...)
327	
328		var cmd *exec.Cmd
329		if a.DeadcodeBin != "" {
330			cmd = exec.Command(a.DeadcodeBin, args...)
331		} else {
332			// Look up deadcode on PATH; fall back to `go run`.
333			if path, err := exec.LookPath("deadcode"); err == nil {
334				cmd = exec.Command(path, args...)
335			} else {
336				full := append([]string{"run", "golang.org/x/tools/cmd/deadcode@v0.42.0"}, args...)
337				cmd = exec.Command("go", full...)
338			}
339		}
340		cmd.Dir = dir
341		var stderr strings.Builder
342		cmd.Stderr = &stderr
343		out, err := cmd.Output()
344		if err != nil {
345			return nil, fmt.Errorf("%v (stderr: %s)", err, strings.TrimSpace(stderr.String()))
346		}
347	
348		var pkgs []deadcodePackage
349		if err := json.Unmarshal(out, &pkgs); err != nil {
